ALLOWED_SCHEMES: Set[str] = {"https"}

# Maximum number of redirects to follow (0 = no redirects for strictest control)
MAX_REDIRECTS: int = 0

# Request timeout in seconds
REQUEST_TIMEOUT: int = 10

# Maximum response size in bytes (5 MB)
MAX_RESPONSE_SIZE: int = 5 * 1024 * 1024


class SSRFProtectionError(Exception):
    """Raised when a request is blocked due to SSRF protection rules."""
    pass


def is_private_ip(ip_str: str) -> bool:
    """Check if an IP address is private, loopback, link-local, or otherwise internal."""
    try:
        ip = ipaddress.ip_address(ip_str)
    except ValueError:
        # If we can't parse it, block it to be safe
        return True

    # Block all private, reserved, loopback, link-local, multicast addresses
    if ip.is_private:
        return True
    if ip.is_loopback:
        return True
    if ip.is_link_local:
        return True
    if ip.is_multicast:
        return True
    if ip.is_reserved:
        return True
    if ip.is_unspecified:
        return True

    # Block IPv4-mapped IPv6 addresses that map to private IPv4
    if isinstance(ip, ipaddress.IPv6Address):
        if ip.ipv4_mapped:
            return is_private_ip(str(ip.ipv4_mapped))
        if ip.sixtofour:
            return is_private_ip(str(ip.sixtofour))
        if ip.teredo:
            # teredo returns (server, client) tuple
            server, client = ip.teredo
            if is_private_ip(str(server)) or is_private_ip(str(client)):
                return True

    # Block AWS metadata service IP ranges
    aws_metadata_ranges = [
        ipaddress.ip_network("169.254.169.254/32"),  # EC2 metadata
        ipaddress.ip_network("fd00:ec2::254/128"),    # EC2 metadata IPv6
    ]
    for network in aws_metadata_ranges:
        if ip in network:
            return True

    # Block common cloud metadata IPs
    cloud_metadata_ips = [
        "169.254.169.254",  # AWS, GCP, Azure metadata
        "100.100.100.200",  # Alibaba Cloud metadata
        "169.254.170.2",    # AWS ECS task metadata
    ]
    if ip_str in cloud_metadata_ips:
        return True

    return False


def validate_url(url: str) -> str:
    """
    Validate a URL against SSRF protections:
    - Must use allowed scheme (HTTPS only)
    - Domain must be in the allowlist
    - Resolved IP must not be private/internal
    
    Returns the validated URL string.
    Raises SSRFProtectionError if validation fails.
    """
    if not url or not isinstance(url, str):
        raise SSRFProtectionError("URL must be a non-empty string")

    url = url.strip()

    # Parse the URL
    try:
        parsed = urlparse(url)
    except Exception as e:
        raise SSRFProtectionError(f"Failed to parse URL: {e}")

    # Validate scheme
    if parsed.scheme not in ALLOWED_SCHEMES:
        raise SSRFProtectionError(
            f"Scheme '{parsed.scheme}' is not allowed. Allowed schemes: {ALLOWED_SCHEMES}"
        )

    # Extract hostname
    hostname = parsed.hostname
    if not hostname:
        raise SSRFProtectionError("URL must contain a valid hostname")

    # Block URLs with credentials
    if parsed.username or parsed.password:
        raise SSRFProtectionError("URLs with embedded credentials are not allowed")

    # Normalize hostname
    hostname = hostname.lower().rstrip(".")

    # Block IP addresses used directly as hostnames
    try:
        ipaddress.ip_address(hostname)
        raise SSRFProtectionError(
            "Direct IP addresses are not allowed. Use a domain name from the allowlist."
        )
    except ValueError:
        # Not an IP address, which is what we want
        pass

    # Strip brackets from IPv6 addresses in URLs like http://[::1]/
    stripped_hostname = hostname.strip("[]")
    try:
        ipaddress.ip_address(stripped_hostname)
        raise SSRFProtectionError(
            "Direct IP addresses (including IPv6) are not allowed."
        )
    except ValueError:
        pass

    # Check domain against allowlist
    if hostname not in ALLOWED_DOMAINS:
        raise SSRFProtectionError(
            f"Domain '{hostname}' is not in the allowed destinations list. "
            f"Contact the platform team to add new integrations."
        )

    # DNS resolution check - ensure the domain doesn't resolve to a private IP
    # This prevents DNS rebinding attacks
    try:
        addr_infos = socket.getaddrinfo(hostname, parsed.port or 443, proto=socket.IPPROTO_TCP)
    except socket.gaierror as e:
        raise SSRFProtectionError(f"DNS resolution failed for '{hostname}': {e}")

    if not addr_infos:
        raise SSRFProtectionError(f"No DNS records found for '{hostname}'")

    for addr_info in addr_infos:
        ip_str = addr_info[4][0]
        if is_private_ip(ip_str):
            raise SSRFProtectionError(
                f"Domain '{hostname}' resolves to private/internal IP '{ip_str}', "
                f"which is blocked for security reasons."
            )

    return url


def validate_redirect(response: requests.Response) -> None:
    """
    Validate redirect targets if redirects are followed.
    This is called as a response hook to check each redirect in the chain.
    """
    if response.is_redirect or response.is_permanent_redirect:
        redirect_url = response.headers.get("Location", "")
        if redirect_url:
            try:
                validate_url(redirect_url)
            except SSRFProtectionError as e:
                raise SSRFProtectionError(
                    f"Redirect to '{redirect_url}' blocked: {e}"
                )


def add_allowed_domain(domain: str) -> None:
    """
    Add a new domain to the allowlist.
    Use this when onboarding new partner integrations.
    """
    normalized = domain.lower().strip().rstrip(".")
    if not re.match(r'^[a-z0-9]([a-z0-9\-]*[a-z0-9])?(\.[a-z0-9]([a-z0-9\-]*[a-z0-9])?)*$', normalized):
        raise ValueError(f"Invalid domain format: '{domain}'")
    ALLOWED_DOMAINS.add(normalized)


def remove_allowed_domain(domain: str) -> None:
    """Remove a domain from the allowlist."""
    normalized = domain.lower().strip().rstrip(".")
    ALLOWED_DOMAINS.discard(normalized)


def get_allowed_domains() -> Set[str]:
    """Return a copy of the current allowlisted domains."""
    return ALLOWED_DOMAINS.copy()


def fetch_url(url: str, method: str = "GET", headers: Optional[dict] = None,
              body: Optional[str] = None) -> dict:
    """
    Safely fetch content from a URL with full SSRF protection.
    
    Args:
        url: The URL to fetch
        method: HTTP method (GET, POST, PUT, etc.)
        headers: Optional request headers
        body: Optional request body for POST/PUT
    
    Returns:
        Dictionary with status_code, headers, and content
    
    Raises:
        SSRFProtectionError: If the URL fails security validation
    """
    # Step 1: Validate the URL before making any request
    validated_url = validate_url(url)

    # Step 2: Prepare the session with strict settings
    session = requests.Session()

    # Disable redirects entirely for strictest control, or limit them
    allow_redirects = MAX_REDIRECTS > 0

    if allow_redirects:
        session.max_redirects = MAX_REDIRECTS
        # Add response hook to validate each redirect target
        session.hooks["response"].append(validate_redirect)

    # Remove any default adapters and add a clean one
    session.mount("https://", HTTPAdapter(max_retries=0))

    # Step 3: Prepare headers - set safe defaults
    request_headers = {
        "User-Agent": "WebhookFetcher/1.0",
        "Accept": "application/json, text/plain, */*",
    }
    if headers:
        # Filter out potentially dangerous headers
        blocked_headers = {"host", "transfer-encoding"}
        for key, value in headers.items():
            if key.lower() not in blocked_headers:
                request_headers[key] = value

    # Step 4: Validate method
    allowed_methods = {"GET", "POST", "PUT", "PATCH", "DELETE", "HEAD", "OPTIONS"}
    method = method.upper()
    if method not in allowed_methods:
        raise SSRFProtectionError(f"HTTP method '{method}' is not allowed")

    # Step 5: Perform DNS resolution again right before the request
    # to minimize the TOCTOU window for DNS rebinding
    parsed = urlparse(validated_url)
    hostname = parsed.hostname
    try:
        addr_infos = socket.getaddrinfo(hostname, parsed.port or 443, proto=socket.IPPROTO_TCP)
        for addr_info in addr_infos:
            ip_str = addr_info[4][0]
            if is_private_ip(ip_str):
                raise SSRFProtectionError(
                    f"DNS rebinding detected: '{hostname}' now resolves to "
                    f"private IP '{ip_str}'"
                )
    except socket.gaierror as e:
        raise SSRFProtectionError(f"DNS resolution failed on second check: {e}")

    # Step 6: Make the request
    try:
        response = session.request(
            method=method,
            url=validated_url,
            headers=request_headers,
            data=body if method in ("POST", "PUT", "PATCH") else None,
            timeout=REQUEST_TIMEOUT,
            allow_redirects=allow_redirects,
            verify=True,  # Always verify SSL certificates
            stream=True,  # Stream to control response size
        )

        # Step 7: Read response with size limit
        content_length = response.headers.get("Content-Length")
        if content_length and int(content_length) > MAX_RESPONSE_SIZE:
            response.close()
            raise SSRFProtectionError(
                f"Response too large: {content_length} bytes "
                f"(max: {MAX_RESPONSE_SIZE} bytes)"
            )

        # Read in chunks to enforce size limit even without Content-Length
        chunks = []
        total_size = 0
        for chunk in response.iter_content(chunk_size=8192):
            total_size += len(chunk)
            if total_size > MAX_RESPONSE_SIZE:
                response.close()
                raise SSRFProtectionError(
                    f"Response exceeded maximum size of {MAX_RESPONSE_SIZE} bytes"
                )
            chunks.append(chunk)

        content = b"".join(chunks)

        result = {
            "status_code": response.status_code,
            "headers": dict(response.headers),
            "content": content.decode("utf-8", errors="replace"),
            "url": response.url,
            "content_length": total_size,
        }

        return result

    except SSRFProtectionError:
        raise
    except requests.exceptions.TooManyRedirects:
        raise SSRFProtectionError(
            f"Too many redirects (max: {MAX_REDIRECTS})"
        )
    except requests.exceptions.SSLError as e:
        raise SSRFProtectionError(f"SSL verification failed: {e}")
    except requests.exceptions.ConnectionError as e:
        raise SSRFProtectionError(f"Connection failed: {e}")
    except requests.exceptions.Timeout:
        raise SSRFProtectionError(
            f"Request timed out after {REQUEST_TIMEOUT} seconds"
        )
    except requests.exceptions.RequestException as e:
        raise SSRFProtectionError(f"Request failed: {e}")
    finally:
        session.close()


def display_response(result: dict) -> None:
    """Display the fetched URL content in a readable format."""
    print(f"\n{'=' * 60}")
    print(f"URL: {result['url']}")
    print(f"Status Code: {result['status_code']}")
    print(f"Content Length: {result['content_length']} bytes")
    print(f"\n--- Response Headers ---")
    for key, value in result["headers"].items():
        print(f"  {key}: {value}")
    print(f"\n--- Response Body ---")
    # Truncate display for very long responses
    content = result["content"]
    if len(content) > 2000:
        print(content[:2000])
        print(f"\n... [truncated, {len(content)} total characters]")
    else:
        print(content)
    print(f"{'=' * 60}\n")


def fetch_and_display(url: str, method: str = "GET",
                      headers: Optional[dict] = None,
                      body: Optional[str] = None) -> dict:
    """
    Main entry point: fetch a URL safely and display its content.
    
    Args:
        url: The URL to fetch
        method: HTTP method
        headers: Optional request headers
        body: Optional request body
    
    Returns:
        Response dictionary
    """
    print(f"Fetching URL: {url}")
    print(f"Method: {method}")

    try:
        result = fetch_url(url, method=method, headers=headers, body=body)
        display_response(result)
        return result
    except SSRFProtectionError as e:
        print(f"\n[BLOCKED] Request denied by SSRF protection: {e}")
        raise


